import pyotp
import hashlib
import secrets
from datetime import datetime, timedelta
from functools import wraps

from flask import Flask, request, jsonify, session, redirect, url_for, render_template_string

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

# In-memory user store (replace with database in production)
USERS_DB = {}
API_KEYS = {}
ACTIVE_SESSIONS = {}


def hash_password(password, salt=None):
    if salt is None:
        salt = secrets.token_hex(16)
    hashed = hashlib.pbkdf2_hmac('sha256', password.encode(), salt.encode(), 100000)
    return salt, hashed.hex()


def verify_password(password, salt, hashed):
    _, computed_hash = hash_password(password, salt)
    return computed_hash == hashed


def generate_session_token():
    return secrets.token_urlsafe(32)


def login_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        session_token = session.get('session_token') or request.headers.get('X-Session-Token')
        if not session_token or session_token not in ACTIVE_SESSIONS:
            return jsonify({'error': 'Authentication required'}), 401
        sess = ACTIVE_SESSIONS[session_token]
        if sess.get('expires_at') and datetime.utcnow() > sess['expires_at']:
            del ACTIVE_SESSIONS[session_token]
            return jsonify({'error': 'Session expired'}), 401
        if sess.get('mfa_pending'):
            return jsonify({'error': 'MFA verification pending'}), 403
        request.current_user = sess['username']
        return f(*args, **kwargs)
    return decorated


def api_key_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key or api_key not in API_KEYS:
            return jsonify({'error': 'Valid API key required'}), 401
        request.current_user = API_KEYS[api_key]['username']
        return f(*args, **kwargs)
    return decorated


