@app.route('/')
def index():
    return redirect(url_for('login'))


@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'GET':
        return render_template_string(REGISTER_PAGE)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')
    confirm_password = request.form.get('confirm_password', '')

    if not username or not password:
        return render_template_string(REGISTER_PAGE, error='Username and password are required')

    if len(password) < 8:
        return render_template_string(REGISTER_PAGE, error='Password must be at least 8 characters')

    if password != confirm_password:
        return render_template_string(REGISTER_PAGE, error='Passwords do not match')

    if username in USERS_DB:
        return render_template_string(REGISTER_PAGE, error='Username already exists')

    salt, hashed = hash_password(password)
    USERS_DB[username] = {
        'salt': salt,
        'password_hash': hashed,
        'mfa_enabled': False,
        'mfa_secret': None,
        'created_at': datetime.utcnow().isoformat()
    }

    return redirect(url_for('login', success='Registration successful. Please login.'))


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET':
        success = request.args.get('success')
        return render_template_string(LOGIN_PAGE, success=success)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')

    if not username or not password:
        return render_template_string(LOGIN_PAGE, error='Username and password are required')

    user = USERS_DB.get(username)
    if not user or not verify_password(password, user['salt'], user['password_hash']):
        return render_template_string(LOGIN_PAGE, error='Invalid username or password')

    session_token = generate_session_token()

    if user['mfa_enabled']:
        # MFA is enabled - create a pending session
        ACTIVE_SESSIONS[session_token] = {
            'username': username,
            'mfa_pending': True,
            'expires_at': datetime.utcnow() + timedelta(minutes=5),  # Short expiry for MFA
            'created_at': datetime.utcnow().isoformat()
        }
        session['session_token'] = session_token
        session['mfa_pending'] = True
        return redirect(url_for('verify_mfa_page'))
    else:
        # No MFA - grant access immediately
        ACTIVE_SESSIONS[session_token] = {
            'username': username,
            'mfa_pending': False,
            'expires_at': datetime.utcnow() + timedelta(hours=24),
            'created_at': datetime.utcnow().isoformat()
        }
        session['session_token'] = session_token
        session.pop('mfa_pending', None)
        return redirect(url_for('dashboard'))


@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa_page():
    if request.method == 'GET':
        session_token = session.get('session_token')
        if not session_token or session_token not in ACTIVE_SESSIONS:
            return redirect(url_for('login'))
        sess = ACTIVE_SESSIONS[session_token]
        if not sess.get('mfa_pending'):
            return redirect(url_for('dashboard'))
        return render_template_string(MFA_PAGE)

    session_token = session.get('session_token')
    if not session_token or session_token not in ACTIVE_SESSIONS:
        return redirect(url_for('login'))

    sess = ACTIVE_SESSIONS[session_token]
    if not sess.get('mfa_pending'):
        return redirect(url_for('dashboard'))

    # Check expiry
    if datetime.utcnow() > sess['expires_at']:
        del ACTIVE_SESSIONS[session_token]
        session.clear()
        return render_template_string(LOGIN_PAGE, error='MFA verification timed out. Please login again.')

    otp = request.form.get('otp', '').strip()
    username = sess['username']
    user = USERS_DB[username]

    totp = pyotp.TOTP(user['mfa_secret'])
    if totp.verify(otp, valid_window=1):
        # MFA verified - upgrade session
        sess['mfa_pending'] = False
        sess['expires_at'] = datetime.utcnow() + timedelta(hours=24)
        session.pop('mfa_pending', None)
        return redirect(url_for('dashboard'))
    else:
        return render_template_string(MFA_PAGE, error='Invalid OTP code. Please try again.')


