@app.route('/setup-mfa')
@login_required
def setup_mfa():
    username = request.current_user
    user = USERS_DB[username]

    if user['mfa_enabled']:
        return redirect(url_for('dashboard'))

    # Generate a new TOTP secret
    secret = pyotp.random_base32()
    session['pending_mfa_secret'] = secret

    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(name=username, issuer_name='FlaskAuthApp')

    return render_template_string(SETUP_MFA_PAGE, secret=secret, provisioning_uri=provisioning_uri)


@app.route('/confirm-mfa', methods=['POST'])
@login_required
def confirm_mfa():
    username = request.current_user
    user = USERS_DB[username]
    secret = session.get('pending_mfa_secret')

    if not secret:
        return redirect(url_for('setup_mfa'))

    otp = request.form.get('otp', '').strip()
    totp = pyotp.TOTP(secret)

    if totp.verify(otp, valid_window=1):
        user['mfa_enabled'] = True
        user['mfa_secret'] = secret
        session.pop('pending_mfa_secret', None)
        return redirect(url_for('dashboard', success='MFA has been enabled successfully!'))
    else:
        provisioning_uri = totp.provisioning_uri(name=username, issuer_name='FlaskAuthApp')
        return render_template_string(
            SETUP_MFA_PAGE,
            secret=secret,
            provisioning_uri=provisioning_uri,
            error='Invalid OTP code. Please try again.'
        )


