@app.route('/api/login', methods=['POST'])
def api_login():
    """Standard API login - respects MFA if enabled."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    user = USERS_DB.get(username)
    if not user or not verify_password(password, user['salt'], user['password_hash']):
        return jsonify({'error': 'Invalid username or password'}), 401

    session_token = generate_session_token()

    if user['mfa_enabled']:
        ACTIVE_SESSIONS[session_token] = {
            'username': username,
            'mfa_pending': True,
            'expires_at': datetime.utcnow() + timedelta(minutes=5),
            'created_at': datetime.utcnow().isoformat()
        }
        return jsonify({
            'message': 'MFA verification required',
            'mfa_required': True,
            'session_token': session_token
        }), 200
    else:
        ACTIVE_SESSIONS[session_token] = {
            'username': username,
            'mfa_pending': False,
            'expires_at': datetime.utcnow() + timedelta(hours=24),
            'created_at': datetime.utcnow().isoformat()
        }
        return jsonify({
            'message': 'Login successful',
            'mfa_required': False,
            'session_token': session_token,
            'username': username
        }), 200


@app.route('/api/verify-mfa', methods=['POST'])
def api_verify_mfa():
    """API endpoint to verify MFA OTP."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    session_token = data.get('session_token') or request.headers.get('X-Session-Token')
    otp = data.get('otp', '').strip()

    if not session_token or session_token not in ACTIVE_SESSIONS:
        return jsonify({'error': 'Invalid or expired session'}), 401

    sess = ACTIVE_SESSIONS[session_token]
    if not sess.get('mfa_pending'):
        return jsonify({'error': 'MFA verification not required'}), 400

    if datetime.utcnow() > sess['expires_at']:
        del ACTIVE_SESSIONS[session_token]
        return jsonify({'error': 'MFA verification timed out'}), 401

    username = sess['username']
    user = USERS_DB[username]

    totp = pyotp.TOTP(user['mfa_secret'])
    if totp.verify(otp, valid_window=1):
        sess['mfa_pending'] = False
        sess['expires_at'] = datetime.utcnow() + timedelta(hours=24)
        return jsonify({
            'message': 'MFA verified successfully',
            'session_token': session_token,
            'username': username
        }), 200
    else:
        return jsonify({'error': 'Invalid OTP code'}), 401


@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    """
    Direct login endpoint for API clients and automated scripts.
    Skips MFA checks entirely - authenticates with password or API key only.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    # Option 1: API key authentication
    api_key = data.get('api_key') or request.headers.get('X-API-Key')
    if api_key:
        if api_key in API_KEYS:
            username = API_KEYS[api_key]['username']
            session_token = generate_session_token()
            ACTIVE_SESSIONS[session_token] = {
                'username': username,
                'mfa_pending': False,
                'expires_at': datetime.utcnow() + timedelta(hours=24),
                'created_at': datetime.utcnow().isoformat(),
                'auth_method': 'api_key'
            }
            return jsonify({
                'message': 'Login successful (API key)',
                'session_token': session_token,
                'username': username,
                'auth_method': 'api_key'
            }), 200
        else:
            return jsonify({'error': 'Invalid API key'}), 401

    # Option 2: Username/password authentication (MFA skipped)
    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Provide username/password or api_key'}), 400

    user = USERS_DB.get(username)
    if not user or not verify_password(password, user['salt'], user['password_hash']):
        return jsonify({'error': 'Invalid username or password'}), 401

    session_token = generate_session_token()
    ACTIVE_SESSIONS[session_token] = {
        'username': username,
        'mfa_pending': False,  # MFA skipped for direct login
        'expires_at': datetime.utcnow() + timedelta(hours=24),
        'created_at': datetime.utcnow().isoformat(),
        'auth_method': 'direct_login'
    }

    return jsonify({
        'message': 'Login successful (direct, MFA skipped)',
        'session_token': session_token,
        'username': username,
        'auth_method': 'direct_login',
        'mfa_skipped': user['mfa_enabled']
    }), 200


